#include <iostream>
#include <vector>
#include <stack>

using namespace std;

void DFS(vector<vector<int>>& graph, int start, vector<bool>& visited) {
    stack<int> s;
    s.push(start);

    while (!s.empty()) {
        int u = s.top();
        s.pop();

        if (!visited[u]) {
            cout << u << " ";
            visited[u] = true;

            for (int v : graph[u]) {
                if (!visited[v]) {
                    s.push(v);
                }
            }
        }
    }
}

int main() {
    int V = 5; // Number of vertices
    vector<vector<int>> graph(V);

    // Adding edges to the graph
    graph[0] = {1, 2};
    graph[1] = {0, 3, 4};
    graph[2] = {0, 4};
    graph[3] = {1};
    graph[4] = {1, 2};

    vector<bool> visited(V, false);

    cout << "DFS traversal starting from vertex 0: ";
    DFS(graph, 0, visited);
    cout << endl;

    return 0;
}
